use std::fmt::Debug;

trait Shape {
    fn calculate_area(&self) -> f64;
    fn describe(&self) -> String;
}

struct Circle { 
    radius: f64,
}
impl Shape for Circle {
    fn calculate_area(&self) -> f64 {
        std::f64::consts::PI * self.radius * self.radius
    }
    fn describe(&self) -> String {
        format!("A circle with radius {}", self.radius)
    }
}

struct Rectangle { 
    width: f64,
    height: f64,
}
impl Shape for Rectangle {
    fn calculate_area(&self) -> f64 {
        self.width * self.height
    }
    fn describe(&self) -> String {
        format!("A rectangle with width {} and height {}", self.width, self.height)
    }
}

fn process_shape(shape: &dyn Shape) -> f64 {
    println!("Processing shape: {}", shape.describe());
    shape.calculate_area()
}

