    let user1 = User { name: String::from("Alice"), id: 42 };
    let product1 = Product { sku: String::from("XYZ-901"), price: 19.99 };

    print_item(&user1);
    print_item(&product1);
}

use std::error::Error;
use std::fmt;

trait Actionable {
    fn execute(&self) -> Result<(), Box<dyn Error>>;
}

struct FastType {}
impl Actionable for FastType {
    fn execute(&self) -> Result<(), Box<dyn Error>> {
        println!("Executing fast action.");
        Ok(())
    }
}

struct SlowType {}
impl Actionable for SlowType {
    fn execute(&self) -> Result<(), Box<dyn Error>> {
        println!("Executing slow action that takes time.");
        Ok(())
    }
}

fn process_collection(items: Vec<Box<dyn Actionable>>) -> Result<(), Box<dyn Error>> {
    for item in items {
        item.execute()?;
    }
    Ok(())
}

fn main() -> Result<(), Box<dyn Error>> {
    let collection: Vec<Box<dyn Actionable>> = vec![ 
        Box::new(FastType {}),
        Box::new(SlowType {}),
        Box::new(FastType {}) 
    ];
    process_collection(collection)?;
    Ok(())
}
